command:
// Pilote les pastilles du Holocron : flags.holocron.statut (allie/ennemi/neutre/
// mentor) + mort + visibilité joueurs. DYNAMIQUE : liste TOUS les journaux du
// dossier « 🎭 Personnages rencontrés » — une nouvelle fiche y apparaît aussitôt,
// sans flag préalable.
try {
const gp = (d, p) => foundry.utils.getProperty(d, p);
const folder = game.folders.find((f) => f.type === "JournalEntry" && f.name === "🎭 Personnages rencontrés");
const pnj = folder
  ? folder.contents
  : game.journal.contents.filter((j) => gp(j, "flags.holocron.kind") === "pc" || gp(j, "flags.holocron.statut"));
if (!pnj.length) return ui.notifications.warn("Aucun journal dans 🎭 Personnages rencontrés — crée-y tes fiches PNJ.");
const esc = (x) => String(x ?? "").replace(/</g, "&lt;").replace(/"/g, "&quot;");
const rows = pnj.map((j) => {
  const st = gp(j, "flags.holocron.statut") || "";
  const dead = !!gp(j, "flags.holocron.mort");
  const vis = (j.ownership?.default ?? 0) >= 2;
  const isNew = !st;
  return `<tr${isNew ? ' style="outline:1px solid #d9b45b55"' : ""}><td><b>${esc(j.name)}</b>${isNew ? ' <span style="color:#d9b45b;font-size:.8em">nouveau</span>' : ""}</td>
    <td><select name="st-${j.id}"><option value="" ${st ? "" : "selected"}>—</option>${["allie","ennemi","neutre","mentor"].map((k) => `<option value="${k}" ${k === st ? "selected" : ""}>${k}</option>`).join("")}</select></td>
    <td style="text-align:center"><input type="checkbox" name="dead-${j.id}" ${dead ? "checked" : ""}/> †</td>
    <td style="text-align:center"><input type="checkbox" name="vis-${j.id}" ${vis ? "checked" : ""}/> 👁</td></tr>`;
}).join("");
const fd = await foundry.applications.api.DialogV2.wait({
  window: { title: "🎭 Statut des PNJ (pastilles Holocron)" },
  content: `<p style="font-size:.85em;opacity:.75">👁 = visible des joueurs sur le Holocron. Une fiche sans statut n'a pas de pastille.</p>
    <table style="width:100%"><thead><tr><th>PNJ</th><th>Statut</th><th>Mort</th><th>Visible</th></tr></thead><tbody>${rows}</tbody></table>`,
  buttons: [{ action: "ok", label: "Appliquer", default: true,
    callback: (e, b) => new (foundry.applications.ux?.FormDataExtended ?? FormDataExtended)(b.form).object },
    { action: "cancel", label: "Annuler" }],
});
if (!fd || fd === "cancel") return;
let changed = 0;
for (const j of pnj) {
  const st = fd[`st-${j.id}`] || "", dead = !!fd[`dead-${j.id}`], vis = !!fd[`vis-${j.id}`];
  const cur = gp(j, "flags.holocron.statut") || "", curDead = !!gp(j, "flags.holocron.mort");
  const curVis = (j.ownership?.default ?? 0) >= 2;
  if (st !== cur || dead !== curDead || vis !== curVis) {
    const upd = { "flags.holocron.mort": dead, "ownership.default": vis ? 2 : 0,
                  "flags.holocron.kind": "pc",
                  "flags.holocron.rev": { updatedAt: Date.now(), updatedBy: game.user.name } };
    if (st) upd["flags.holocron.statut"] = st; else upd["flags.holocron.-=statut"] = null;
    await j.update(upd);
    changed++;
  }
}
ui.notifications.info(`${changed} fiche(s) mise(s) à jour — Holocron à jour à la prochaine sync.`);
} catch (e) { console.error("[Statut PNJ]", e); ui.notifications.error("Statut PNJ : " + (e?.message || e)); }
